api.signature:
struct {
	// MinXPPM is the inclusive horizontal X-axis lower bound.
	MinXPPM	uint32	`json:"min_x_ppm"`
	// MaxXPPM is the inclusive horizontal X-axis upper bound.
	MaxXPPM	uint32	`json:"max_x_ppm"`
	// MinYPPM is the inclusive horizontal Y-axis lower bound.
	MinYPPM	uint32	`json:"min_y_ppm"`
	// MaxYPPM is the inclusive horizontal Y-axis upper bound.
	MaxYPPM	uint32	`json:"max_y_ppm"`
	// MinZPPM is the inclusive vertical Z-axis lower bound.
	MinZPPM	uint32	`json:"min_z_ppm"`
	// MaxZPPM is the inclusive vertical Z-axis upper bound.
	MaxZPPM	uint32	`json:"max_z_ppm"`
}

struct {
	// ID is the unique deterministic instance identity.
	ID	string	`json:"id"`
	// TypeID refers to a NormalizedContainer.ID in the request.
	TypeID	string	`json:"type_id"`
}

struct {
	// ID is the required unique type identity.
	ID	string
	// InternalDimensions are the exact usable physical lengths.
	InternalDimensions	PhysicalDimensions
	// ExternalDimensions optionally describe non-feasibility shipping size.
	ExternalDimensions	*PhysicalDimensions
	// MaxContentWeight is the exact positive content mass limit.
	MaxContentWeight	measurement.Quantity
	// TareWeight is the optional non-negative empty-container mass.
	TareWeight	*measurement.Quantity
	// MaxGrossWeight optionally limits tare plus content mass.
	MaxGrossWeight	*measurement.Quantity
	// Stock explicitly selects finite or unlimited availability.
	Stock	Stock
	// Priority is the deterministic type ordering after objective equivalence.
	Priority	int64
	// MaxItemCount limits placements per instance; zero means unrestricted.
	MaxItemCount	uint32
	// AllowedClasses is a copied canonical allowlist for item class attributes.
	AllowedClasses	[]string
	// Reserved is a copied set of unusable cuboids inside internal dimensions.
	Reserved	[]ReservedRegion
	// CenterOfGravity optionally constrains the combined content mass center.
	CenterOfGravity	*CenterOfGravityBounds
}

struct {
	// Code is the stable diagnostic category.
	Code	string	`json:"code"`
	// ItemID optionally scopes the diagnostic to an item.
	ItemID	string	`json:"item_id,omitempty"`
	// ContainerID optionally scopes the diagnostic to an instance or type.
	ContainerID	string	`json:"container_id,omitempty"`
	// Message is the bounded human-readable explanation.
	Message	string	`json:"message"`
}

struct {
	// Category is the stable sentinel returned by Unwrap.
	Category	error
	// Field is the machine-readable input field name when known.
	Field	string
	// ID is the affected item or container ID when known.
	ID	string
	// Reason is the human-readable validation detail.
	Reason	string
}

struct {
	// ID is the required unique logical item identity.
	ID	string
	// SKU is optional caller metadata and does not establish identity.
	SKU	string
	// Dimensions are exact positive physical lengths.
	Dimensions	PhysicalDimensions
	// Weight is the exact positive item mass.
	Weight	measurement.Quantity
	// Orientations is the nonempty allowed physical-axis permutation set.
	Orientations	[]geometry.Orientation
	// Attributes is copied caller metadata used by eligibility constraints.
	Attributes	map[string]string
	// FragileTop forbids any item from using this item as a supporter.
	FragileTop	bool
	// MaxSupportedWeight is the optional non-negative total transitive load.
	MaxSupportedWeight	*measurement.Quantity
	// MinimumSupportPPM is the required supported footprint in millionths.
	MinimumSupportPPM	uint32
	// Group requires all same-group items to share one container.
	Group	string
	// IncompatibleGroups may not share a container with this item.
	IncompatibleGroups	[]string
	// MaxStackCount bounds the number of supported levels above this item; zero
	// means no stack-depth constraint.
	MaxStackCount	uint32
	// Priority is an exact caller value used by PackedPriority objectives.
	Priority	int64
}

struct {
	// MaxItems bounds normalized item instances.
	MaxItems	uint32
	// MaxContainerTypes bounds distinct container definitions.
	MaxContainerTypes	uint32
	// MaxOrientations bounds allowed orientations per item.
	MaxOrientations	uint32
	// MaxCandidatePlacements bounds heuristic and exact placement attempts.
	MaxCandidatePlacements	uint64
	// MaxSearchNodes bounds exact-search states.
	MaxSearchNodes	uint64
	// MaxBranches bounds exact-search edges and container configurations.
	MaxBranches	uint64
	// MaxImprovementRounds bounds complete heuristic repacking passes.
	MaxImprovementRounds	uint32
	// MaxMemoryBytes bounds conservative request and solver working estimates.
	MaxMemoryBytes	uint64
	// MaxIDBytes bounds each item, type, and instance identifier.
	MaxIDBytes	uint32
	// MaxDiagnostics bounds verifier and solver diagnostic collections.
	MaxDiagnostics	uint32
}

struct {
	// ID is the unique container type identity.
	ID	string
	// Dimensions are positive usable length-lattice counts.
	Dimensions	geometry.Dimensions
	// MaxContentWeight is the positive content mass-lattice limit.
	MaxContentWeight	int64
	// TareWeight is the non-negative empty-container mass-lattice value.
	TareWeight	int64
	// MaxGrossWeight is tare plus content capacity when HasGrossWeight is true.
	MaxGrossWeight	int64
	// HasGrossWeight distinguishes an absent limit from a numeric value.
	HasGrossWeight	bool
	// Stock explicitly selects finite or unlimited type availability.
	Stock	Stock
	// Priority is the deterministic type-ordering value.
	Priority	int64
	// MaxItemCount limits placements per instance; zero is unrestricted.
	MaxItemCount	uint32
	// AllowedClasses is a copied item-class allowlist.
	AllowedClasses	[]string
	// Reserved is a copied set of unusable cuboids inside Dimensions.
	Reserved	[]geometry.Cuboid
	// CenterOfGravity optionally bounds combined content mass by axis PPM.
	CenterOfGravity	*CenterOfGravityBounds
}

struct {
	// ID is the unique logical item identity.
	ID	string
	// SKU is optional non-identity metadata.
	SKU	string
	// Dimensions are positive length-lattice counts.
	Dimensions	geometry.Dimensions
	// Weight is a positive mass-lattice count.
	Weight	int64
	// Orientations is the canonical nonempty allowed permutation set.
	Orientations	[]geometry.Orientation
	// Attributes is copied metadata used by eligibility constraints.
	Attributes	map[string]string
	// FragileTop forbids supported placements above this item.
	FragileTop	bool
	// MaxSupportedWeight is an optional non-negative mass-lattice load limit.
	MaxSupportedWeight	*int64
	// MinimumSupportPPM is required footprint support in millionths.
	MinimumSupportPPM	uint32
	// Group requires co-location with all items carrying the same value.
	Group	string
	// IncompatibleGroups may not share a container with this item.
	IncompatibleGroups	[]string
	// MaxStackCount bounds supported levels above; zero is unrestricted.
	MaxStackCount	uint32
	// Priority is the exact PackedPriority objective contribution.
	Priority	int64
}

struct {
	// Items are already expressed in the selected integer lattice.
	Items	[]NormalizedItem
	// Containers are already expressed in the selected integer lattice.
	Containers	[]NormalizedContainer
	// Resolution preserves the exact physical meaning of lattice units.
	Resolution	Resolution
	// Limits bounds construction, solving, verification, and diagnostics.
	Limits	Limits
}

struct {
	// X is the exact physical width.
	X	measurement.Quantity
	// Y is the exact physical depth.
	Y	measurement.Quantity
	// Z is the exact physical height.
	Z	measurement.Quantity
}

struct {
	// ItemID refers to exactly one NormalizedItem.ID.
	ItemID	string	`json:"item_id"`
	// ContainerID refers to one ContainerInstance.ID.
	ContainerID	string	`json:"container_id"`
	// Origin is the non-negative lower lattice corner.
	Origin	geometry.Point	`json:"origin"`
	// Orientation is the selected allowed physical-axis permutation.
	Orientation	geometry.Orientation	`json:"orientation"`
	// Dimensions are the recomputable oriented lattice lengths.
	Dimensions	geometry.Dimensions	`json:"dimensions"`
	// Weight is the recomputable item mass-lattice count.
	Weight	int64	`json:"weight"`
	// SupporterIDs is the canonical set of items with positive contact beneath.
	SupporterIDs	[]string	`json:"supporter_ids,omitempty"`
	// Diagnostics is bounded non-authoritative placement metadata.
	Diagnostics	[]Diagnostic	`json:"diagnostics,omitempty"`
}

struct {
	// MaxContainers bounds selected instance records.
	MaxContainers	uint32
	// MaxPlacements bounds placement records.
	MaxPlacements	uint32
	// MaxUnpackedItems bounds partial-result identity records.
	MaxUnpackedItems	uint32
	// MaxObjectiveComponents bounds lexicographic score records.
	MaxObjectiveComponents	uint32
	// MaxDiagnostics bounds plan and placement diagnostics combined.
	MaxDiagnostics	uint32
	// MaxIDBytes bounds every item, type, instance, and supporter ID.
	MaxIDBytes	uint32
	// MaxMetadataBytes bounds each diagnostic and objective string.
	MaxMetadataBytes	uint32
	// MaxBytes bounds the conservative owned plan-size estimate.
	MaxBytes	uint64
}

struct {
	// Containers is the selected canonical container instance list.
	Containers	[]ContainerInstance	`json:"containers"`
	// Placements contains at most one entry for each packed item.
	Placements	[]Placement	`json:"placements"`
	// UnpackedItemIDs identifies omitted items for permitted partial plans.
	UnpackedItemIDs	[]string	`json:"unpacked_item_ids"`
	// Objective contains exact components in precedence order.
	Objective	[]ScoreComponent	`json:"objective"`
	// Status states the level of feasibility or proof claimed.
	Status	Status	`json:"status"`
	// Termination states why solver work stopped.
	Termination	TerminationReason	`json:"termination"`
	// Statistics contains independently recomputable aggregates.
	Statistics	Statistics	`json:"statistics"`
	// Work contains deterministic bounded search counters.
	Work	Work	`json:"work"`
	// Diagnostics contains bounded non-authoritative plan metadata.
	Diagnostics	[]Diagnostic	`json:"diagnostics"`
}

struct {
	// Origin is the non-negative lower lattice corner.
	Origin	geometry.Point
	// Dimensions are exact positive physical lengths.
	Dimensions	PhysicalDimensions
}

struct {
	// Length is the exact coordinate and dimension lattice step.
	Length	measurement.Quantity
	// Mass is the exact weight and load lattice step.
	Mass	measurement.Quantity
}

struct {
	// Name is the stable objective metric identifier.
	Name	string	`json:"name"`
	// Direction is either "min" or "max".
	Direction	string	`json:"direction"`
	// Unit identifies the exact count, lattice, priority, or currency domain.
	Unit	string	`json:"unit"`
	// Value is the canonical exact decimal representation.
	Value	string	`json:"value"`
}

struct {
	// PackedItems is the placement count.
	PackedItems	uint32	`json:"packed_items"`
	// ContainerCount is the selected instance count.
	ContainerCount	uint32	`json:"container_count"`
	// ItemWeight is total packed mass in request lattice units.
	ItemWeight	int64	`json:"item_weight"`
	// ItemVolume is total packed volume in cubed length-lattice units.
	ItemVolume	int64	`json:"item_volume"`
	// ContainerVolume is total selected usable lattice volume.
	ContainerVolume	int64	`json:"container_volume"`
	// RemainingWeight is unused content capacity in mass-lattice units.
	RemainingWeight	int64	`json:"remaining_weight"`
	// RemainingVolume is container volume minus item volume.
	RemainingVolume	int64	`json:"remaining_volume"`
}

struct {
	// Solver is the stable solver implementation identifier.
	Solver	string	`json:"solver"`
	// Strategy is the stable search-strategy identifier.
	Strategy	string	`json:"strategy"`
	// Seed is the caller-provided reproducibility value.
	Seed	uint64	`json:"seed"`
	// Nodes is the number of exact-search states entered.
	Nodes	uint64	`json:"nodes"`
	// Branches is the number of exact-search edges or configurations considered.
	Branches	uint64	`json:"branches"`
	// CandidatePlacements is the number of orientation-position attempts.
	CandidatePlacements	uint64	`json:"candidate_placements"`
	// ImprovementRounds is the number of complete heuristic repacking passes.
	ImprovementRounds	uint32	`json:"improvement_rounds"`
}

struct {
	// Accepted reports whether packing may retain the candidate.
	Accepted	bool
	// Code is the stable application rejection identifier.
	Code	string
	// Message is the bounded human-readable rejection explanation.
	Message	string
}

interface {
	// Check decides whether the immutable candidate view is acceptable.
	Check(context.Context, PlacementView) Decision
}

struct {
	item		knapsack.NormalizedItem
	container	knapsack.NormalizedContainer
	candidate	knapsack.Placement
	placements	[]knapsack.Placement
}

struct {
	// MaxBytes is the maximum UTF-8 JSON byte length.
	MaxBytes	int64
	// MaxDepth is the maximum nested object or array depth.
	MaxDepth	int
	// MaxCollection is the maximum members in any one object or array.
	MaxCollection	int
}

struct {
	origin	Point
	dims	Dimensions
	max	Point
}

struct {
	// X, Y, and Z are positive lattice lengths.
	X, Y, Z int64
}

struct {
	// X, Y, and Z are non-negative lattice coordinates.
	X, Y, Z int64
}

struct {
	// Metric is the exact plan property to evaluate.
	Metric	Metric
	// Direction selects minimization or maximization.
	Direction	Direction
}

interface {
	Valid() bool
	ComparePlans(context.Context, knapsack.NormalizedRequest, knapsack.Plan, knapsack.Plan) (int, error)
	Components(context.Context, knapsack.NormalizedRequest, knapsack.Plan) ([]knapsack.ScoreComponent, error)
}

struct {
	// Values correspond positionally to Objective.Criteria.
	Values	[]int64
	// TieBreak is compared lexically only after every criterion is equal.
	TieBreak	string
}

struct {
	// MaxTypes bounds configured container type costs.
	MaxTypes	uint32
	// MaxIDBytes bounds each container type identifier.
	MaxIDBytes	uint32
}

struct {
	// Seed is recorded for reproducibility; built-in solvers use no ambient
	// randomness.
	Seed	uint64
	// AllowUnpacked permits verified best-known plans that omit items.
	AllowUnpacked	bool
	// Constraints are synchronous bounded custom placement predicates.
	Constraints	[]constraint.Placement
	// Objective is the built-in exact lexicographic objective. It conflicts
	// with PlanObjective when both are set.
	Objective	objective.Objective
	// PlanObjective is a custom complete-plan comparison extension.
	PlanObjective	objective.PlanObjective
}

struct {
	requireAll	bool
	objective	objective.PlanObjective
	constraints	[]constraint.Placement
	constraintErr	error
}

struct {
	violations	[]Violation
	maximum		uint32
	truncated	bool
	err		error
}

struct {
	// Code is the stable machine-readable category.
	Code	Code
	// ItemID identifies the affected item, or is empty for plan-wide findings.
	ItemID	string
	// ContainerID identifies the affected instance or type when applicable.
	ContainerID	string
	// Message is a bounded human-readable explanation.
	Message	string
}
